starterCode.javascript:
function useMemoizedArray(initialArray, dependencyArray) {
  const memoizedArray = useRef(initialArray);
  const updateMemoizedArray = useCallback((newDependencyArray) => {
    if (JSON.stringify(memoizedArray.current) === JSON.stringify(newDependencyArray)) {
      return;
    }
    memoizedArray.current = newDependencyArray;
  }, []);
  return [memoizedArray.current, updateMemoizedArray];
}

